	DECLARE @madonhang nvarchar(200);
	DECLARE @hehang nvarchar(200);
	DECLARE @makhachhang nvarchar(50);
	DECLARE @masp nvarchar(200);
	DECLARE @tensp nvarchar(200);
	DECLARE @soluong int;

	DECLARE CUR CURSOR LOCAL FOR
		SELECT A.order_number, A.[range] AS hehang, A.customer AS khachhang,
			C.masp, C.tensp, B.order_qty
		FROM tr_order A
		INNER JOIN tr_order_detail B ON A.order_number = B.order_number
		INNER JOIN tr_sanpham C ON B.item_number = C.masp
		WHERE A.f_cancelled = 'N' AND B.f_cancelled = 'N'
			AND A.order_number = @donhang
	OPEN CUR;
	FETCH NEXT FROM CUR INTO @madonhang, @hehang, @makhachhang, @masp, @tensp, @soluong;
	WHILE @@FETCH_STATUS = 0
	BEGIN
		IF NOT EXISTS (SELECT 1 FROM tr_kehoach_mau3 WHERE madonhang = @madonhang AND masp = @masp)
		BEGIN
			INSERT INTO tr_kehoach_mau3
			(
				madonhang, 
				hehang, 
				khachhang, 
				masp, 
				tensp, 
				soluong, 
				uutien, 
				ngaytao, 
				nguoitao
			) VALUES (
				@madonhang,
				@hehang,
				@makhachhang,
				@masp,
				@tensp,
				@soluong,
				NULL,
				GETDATE(),
				@nguoitao
			)
		END
		
		FETCH NEXT FROM CUR INTO @madonhang, @hehang, @makhachhang, @masp, @tensp, @soluong;
	END
	CLOSE CUR;
